// ==================== BOLT IMPLEMENTATIONS ====================

class ValidationBolt {

    private static final Map<String, double[]> VALID_RANGES = new ConcurrentHashMap<>();
    static {
        VALID_RANGES.put("vibration", new double[]{0, 100});
        VALID_RANGES.put("temperature", new double[]{-20, 200});
        VALID_RANGES.put("pressure", new double[]{0, 1000});
    }

    private long processedCount = 0;
    private long invalidCount = 0;

    public Optional<SensorReading> process(SensorReading reading) {
        if (reading == null) return Optional.empty();

        String sensorType = reading.getSensorType();
        double value = reading.getValue();

        if (!VALID_RANGES.containsKey(sensorType)) {
            invalidCount++;
            return Optional.empty();
        }

        double[] range = VALID_RANGES.get(sensorType);
        if (value < range[0] || value > range[1]) {
            invalidCount++;
            return Optional.empty();
        }

        processedCount++;
        return Optional.of(reading);
    }

    public long getProcessedCount() { return processedCount; }
    public long getInvalidCount() { return invalidCount; }
}

class AnomalyDetectionBolt {

    private static final Map<String, double[]> THRESHOLDS = new ConcurrentHashMap<>();
    static {
        THRESHOLDS.put("vibration", new double[]{70, 85});
        THRESHOLDS.put("temperature", new double[]{150, 180});
        THRESHOLDS.put("pressure", new double[]{800, 900});
    }

    private final int maxHistory;
    private final Map<String, List<Double>> history = new ConcurrentHashMap<>();
    private long anomalyCount = 0;

    public AnomalyDetectionBolt(int maxHistory) {
        this.maxHistory = maxHistory;
    }

    public Optional<AnomalyResult> process(SensorReading reading) {
        if (reading == null) return Optional.empty();

        String machineId = reading.getMachineId();
        String sensorType = reading.getSensorType();
        double value = reading.getValue();
        long timestamp = reading.getTimestamp();

        String key = machineId + ":" + sensorType;

        // Maintain history for statistical analysis
        history.computeIfAbsent(key, k -> new ArrayList<>()).add(value);
        List<Double> hist = history.get(key);

        // Trim history
        synchronized(hist) {
            while (hist.size() > maxHistory) {
                hist.remove(0);
            }
        }

        // Initialize severity
        String severity = "normal";
        double zScore = 0.0;

        // Threshold-based detection
        if (THRESHOLDS.containsKey(sensorType)) {
            double[] threshold = THRESHOLDS.get(sensorType);

            if (value >= threshold[1]) {
                severity = "critical";
                anomalyCount++;
            } else if (value >= threshold[0]) {
                severity = "warning";
            }
        }

        // Statistical detection (3-sigma rule)
        synchronized(hist) {
            if (hist.size() >= 10) {
                double mean = hist.stream().mapToDouble(d -> d).average().orElse(0);
                double variance = hist.stream()
                    .mapToDouble(d -> Math.pow(d - mean, 2))
                    .average().orElse(0);
                double std = Math.sqrt(variance);

                if (std > 0) {
                    zScore = Math.abs((value - mean) / std);

                    if (zScore > 3) {
                        severity = "critical";
                        anomalyCount++;
                    }
                }
            }
        }

        return Optional.of(new AnomalyResult(
            machineId, sensorType, value, timestamp, severity, zScore
        ));
    }

    public long getAnomalyCount() { return anomalyCount; }
}

class SlidingWindowBolt {

    private final int windowSizeSeconds;
    private final int slideIntervalSeconds;
    private final Map<String, List<WindowData>> windows = new ConcurrentHashMap<>();
    private final Map<String, Long> lastEmit = new ConcurrentHashMap<>();

    private static class WindowData {
        double value;
        long timestamp;
        String severity;

        WindowData(double value, long timestamp, String severity) {
            this.value = value;
            this.timestamp = timestamp;
            this.severity = severity;
        }
    }

    public SlidingWindowBolt(int windowSizeSeconds, int slideIntervalSeconds) {
        this.windowSizeSeconds = windowSizeSeconds;
        this.slideIntervalSeconds = slideIntervalSeconds;
    }

    public Optional<WindowAggregation> process(AnomalyResult result) {
        if (result == null) return Optional.empty();

        String key = result.getMachineId() + ":" + result.getSensorType();
        long currentTime = result.getTimestamp() / 1000; // ms to seconds

        // Add to window buffer
        windows.computeIfAbsent(key, k -> new ArrayList<>())
            .add(new WindowData(result.getValue(), currentTime, result.getSeverity()));

        List<WindowData> window = windows.get(key);

        // Remove expired data
        long cutoff = currentTime - windowSizeSeconds;
        synchronized(window) {
            window.removeIf(w -> w.timestamp < cutoff);

            // Emit at slide intervals
            Long lastEmitTime = lastEmit.get(key);

            if (lastEmitTime == null || (currentTime - lastEmitTime) >= slideIntervalSeconds) {
                if (!window.isEmpty()) {
                    List<Double> values = window.stream()
                        .map(w -> w.value)
                        .collect(Collectors.toList());

                    List<String> severities = window.stream()
                        .map(w -> w.severity)
                        .collect(Collectors.toList());

                    WindowAggregation agg = new WindowAggregation(
                        result.getMachineId(),
                        result.getSensorType(),
                        window.stream().mapToLong(w -> w.timestamp).min().orElse(0),
                        currentTime,
                        values.size(),
                        values.stream().mapToDouble(d -> d).average().orElse(0),
                        values.stream().mapToDouble(d -> d).min().orElse(0),
                        values.stream().mapToDouble(d -> d).max().orElse(0),
                        (int) severities.stream().filter(s -> s.equals("critical")).count(),
                        (int) severities.stream().filter(s -> s.equals("warning")).count()
                    );

                    lastEmit.put(key, currentTime);
                    return Optional.of(agg);
                }
            }
        }

        return Optional.empty();
    }
}

