public class IndustrialMonitoringTopology {

    public static void main(String[] args) {
        System.out.println("========================================");
        System.out.println("Real-time IoT Monitoring with Storm");
        System.out.println("========================================\n");

        // Show topology configuration
        StormTopologyBuilder.buildTopology();

        // Initialize components
        ValidationBolt validationBolt = new ValidationBolt();
        AnomalyDetectionBolt anomalyBolt = new AnomalyDetectionBolt(100);
        SlidingWindowBolt windowBolt = new SlidingWindowBolt(60, 10);

        // Simulate processing
        Random random = new Random();
        String[] machines = {"MACHINE_0001", "MACHINE_0002", "MACHINE_0003"};
        String[] sensors = {"vibration", "temperature", "pressure"};

        System.out.println("\n--- Simulating Sensor Data Processing ---\n");

        for (int i = 0; i < 50; i++) {
            String machineId = machines[random.nextInt(machines.length)];
            String sensorType = sensors[random.nextInt(sensors.length)];
            double value = random.nextDouble() * 200;
            long timestamp = System.currentTimeMillis();

            // Create sensor reading
            SensorReading reading = new SensorReading(machineId, sensorType, value, timestamp);

            // Process through topology
            Optional<SensorReading> validated = validationBolt.process(reading);
            Optional<AnomalyResult> anomaly = anomalyBolt.process(validated.orElse(null));
            Optional<WindowAggregation> windowAgg = windowBolt.process(anomaly.orElse(null));

            // Display anomalies
            if (anomaly.isPresent() && !anomaly.get().getSeverity().equals("normal")) {
                AnomalyResult a = anomaly.get();
                System.out.printf("[%s] %s | %s | Value: %.2f | Z-Score: %.2f%n",
                    a.getSeverity().toUpperCase(),
                    a.getMachineId(),
                    a.getSensorType(),
                    a.getValue(),
                    a.getZScore());
            }
        }

        System.out.println("\n--- Statistics ---");
        System.out.println("Valid readings: " + validationBolt.getProcessedCount());
        System.out.println("Invalid readings filtered: " + validationBolt.getInvalidCount());
        System.out.println("Anomalies detected: " + anomalyBolt.getAnomalyCount());
    }
}
